#include<bits/stdc++.h>
using namespace std;
int mp[1050],n,m,now,ans=0;
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            char ch;
            scanf("%s",&ch);
            if(ch=='R')
            {
                mp[j]=0;
            }
            else
            {
                mp[j]++;
            }
            now=mp[j];
            ans=max(ans,now);
            for(int k=j-1;k>=1&&mp[k];k--)
            {
                now=min(now,mp[k]);
                ans=max(ans,now*(j-k+1));
            }
        }
    }
    printf("%d",ans*3);
    return 0;
}
